def pick_role_event(role: str, pack: str | None = None) -> dict:
    from engine.apprentice_roles import role_event_key
    key = role_event_key(role)
    pool = ROLE_EVENTS.get(role) or ROLE_EVENTS.get(key) or ROLE_EVENTS.get('hunter', [])
    event = random.choice(pool)
    variants = event.get('pack_variants')
    if pack and variants and pack in variants:
        merged = dict(event)
        merged.update(variants[pack])
        merged.pop('pack_variants', None)
        return merged
    return event

def pick_prophecy() -> str:
    return random.choice(DROWN_PROPHECIES)
